# ============================================================
# 1. Compute execution frequency of each line across attempts
# ============================================================
line_freq = Counter()
for cov in coverage.values():
    line_freq.update(cov)

print("\n=== Top 20 Most Frequently Hit Lines ===")
for line, freq in line_freq.most_common(20):
    print(f"Line {line}: {freq} attempts")

# ============================================================
# 2. Build similarity graph using Jaccard similarity
# ============================================================
G = nx.Graph()

# Add nodes first
for attempt in coverage:
    G.add_node(attempt)

# Add weighted edges between attempts with similarity > threshold
SIM_THRESHOLD = 0.7

def jaccard(a, b):
    return len(a & b) / len(a | b)

for (i, cov_i), (j, cov_j) in combinations(coverage.items(), 2):
    sim = jaccard(cov_i, cov_j)
    if sim >= SIM_THRESHOLD:
        G.add_edge(i, j, weight=sim)

print(f"\nGraph built with {G.number_of_nodes()} nodes and {G.number_of_edges()} edges.")

# ============================================================
# 3. Compute centrality measures
# ============================================================
deg_cent = nx.degree_centrality(G)
close_cent = nx.closeness_centrality(G)
bet_cent = nx.betweenness_centrality(G, k=50, seed=0)  # sample for speed

print("\n=== Top 10 Attempts by Degree Centrality ===")
for a, score in sorted(deg_cent.items(), key=lambda x: -x[1])[:10]:
    print(f"Attempt {a}: {score:.4f}")

# ============================================================
# 4. Community detection (Louvain-like using greedy modularity)
# ============================================================
communities = nx.algorithms.community.greedy_modularity_communities(G)
communities = list(communities)

print(f"\nDetected {len(communities)} communities.")
for idx, comm in enumerate(communities[:5]):
    print(f"  Community {idx}: size={len(comm)}")


# ============================================================
# 5. Cluster-level statistics
# ============================================================
def cluster_summary(cluster):
    """Compute consensus coverage characteristics."""
    cluster_cov = [coverage[c] for c in cluster]
    union = set().union(*cluster_cov)
    intersection = set.intersection(*cluster_cov) if cluster_cov else set()
    return {
        "size": len(cluster),
        "avg_cov_size": sum(len(c) for c in cluster_cov) / len(cluster),
        "union_size": len(union),
        "intersection_size": len(intersection),
    }

print("\n=== Cluster Summaries ===")
for idx, comm in enumerate(communities[:5]):
    s = cluster_summary(comm)
    print(f"Cluster {idx}: {s}")

# ============================================================
# 6. Optional: Export the similarity graph
# ============================================================
nx.write_gexf(G, "coverage_similarity_graph.gexf")
print("\nGraph exported to: coverage_similarity_graph.gexf")
